<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>대치동 수리셈</title>
  <script src="js/common.js?v=<?= filemtime('js/common.js') ?>"></script>
  <style>
    *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

    :root {
      --navy:   #0D2B6B;
      --red:    #E8292A;
      --orange: #F47920;
      --white:  #ffffff;
      --nav-h:  62px;
    }

    html, body { width: 100%; background: #fff; font-family: 'Apple SD Gothic Neo', 'Noto Sans KR', sans-serif; }

    /* ══ HEADER ══ */
    header {
      position: sticky;
      top: 0;
      z-index: 500;
      height: var(--nav-h);
      background: var(--navy);
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0 28px;
      box-shadow: 0 2px 10px rgba(0,0,0,.4);
    }

    .logo {
      font-size: 1.2rem;
      font-weight: 900;
      color: var(--white);
      letter-spacing: -0.5px;
      white-space: nowrap;
    }
    .logo span { color: var(--orange); }

    /* ── 데스크톱 nav ── */
    nav {
      display: flex;
      align-items: center;
      gap: 6px;
    }

    nav a, nav button {
      display: inline-flex;
      align-items: center;
      gap: 5px;
      padding: 7px 16px;
      border-radius: 22px;
      font-size: .88rem;
      font-weight: 700;
      text-decoration: none;
      border: none;
      cursor: pointer;
      transition: background .2s, color .2s, transform .15s;
      white-space: nowrap;
      background: transparent;
      color: rgba(255,255,255,.82);
    }

    nav a:hover, nav button:hover {
      background: rgba(255,255,255,.13);
      color: #fff;
      transform: translateY(-1px);
    }

    nav .btn-primary {
      background: var(--red);
      color: #fff;
      padding: 7px 18px;
    }
    nav .btn-primary:hover { background: #c51f20; color: #fff; }

    nav .btn-outline {
      border: 1.5px solid rgba(255,255,255,.4);
      color: #fff;
    }
    nav .btn-outline:hover { border-color: var(--orange); color: var(--orange); background: transparent; }

    nav .ico { font-style: normal; font-size: 1rem; }

    /* ── 햄버거 ── */
    .hamburger {
      display: none;
      flex-direction: column;
      gap: 5px;
      cursor: pointer;
      padding: 6px;
      background: none;
      border: none;
    }
    .hamburger span {
      display: block;
      width: 24px;
      height: 2px;
      background: #fff;
      border-radius: 2px;
    }

    /* ── 모바일 드로어 ── */
    .mobile-menu {
      display: none;
      position: fixed;
      top: var(--nav-h);
      left: 0; right: 0;
      background: var(--navy);
      z-index: 490;
      padding: 16px 20px 24px;
      flex-direction: column;
      gap: 6px;
      box-shadow: 0 8px 24px rgba(0,0,0,.4);
    }
    .mobile-menu.open { display: flex; }
    .mobile-menu a, .mobile-menu button {
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 11px 16px;
      border-radius: 10px;
      font-size: .95rem;
      font-weight: 700;
      color: rgba(255,255,255,.88);
      text-decoration: none;
      background: none;
      border: none;
      cursor: pointer;
      transition: background .2s;
      text-align: left;
    }
    .mobile-menu a:hover, .mobile-menu button:hover { background: rgba(255,255,255,.1); color: #fff; }
    .mobile-menu .btn-primary { background: var(--red); color: #fff; }
    .mobile-menu .btn-primary:hover { background: #c51f20; }
    .mobile-menu hr { border: none; border-top: 1px solid rgba(255,255,255,.12); margin: 4px 0; }

    /* ══ COVER ══ */
    #cover {
      position: relative;
      width: 100%;
      aspect-ratio: 16 / 9;
      background-position: center;
      background-repeat: no-repeat;
      background-size: cover;
      cursor: pointer;
      line-height: 0;
      display: block;
    }
    #cover img {
      display: none;
    }
    #cover::before {
      content: '';
      position: absolute;
      inset: 0;
      background: rgba(0,0,0,0);
      transition: background .25s;
    }
    #cover:hover::before { background: rgba(0,0,0,.14); }

    .play-btn {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 82px;
      height: 82px;
      border-radius: 50%;
      background: rgba(255,255,255,.9);
      display: flex;
      align-items: center;
      justify-content: center;
      box-shadow: 0 4px 28px rgba(0,0,0,.35);
      pointer-events: none;
      transition: transform .25s, background .2s;
    }
    #cover:hover .play-btn {
      transform: translate(-50%, -50%) scale(1.13);
      background: #fff;
    }
    .play-btn svg { width: 34px; height: 34px; fill: var(--red); margin-left: 5px; }

    .online-study-wrap {
      position: absolute;
      left: 0;
      right: 0;
      bottom: 4%;
      z-index: 2;
      padding: 0 20px;
      text-align: center;
      line-height: normal;
    }
    .online-study-btn {
      display: inline-block;
      width: min(450px, 90vw);
      padding: 12px 24px;
      border: 0;
      border-radius: 20px;
      background: #4ec476;
      color: #fff;
      box-shadow: 4px -3px 8px 4px #d0d0d0aa;
      font-size: clamp(1.5rem, 3vw, 2.5rem);
      font-weight: 900;
      cursor: pointer;
    }
    .online-study-btn:hover { background: #41b969; }

    /* ══ MODAL ══ */
    .modal-overlay {
      display: none;
      position: fixed;
      inset: 0;
      z-index: 999;
      background: rgba(0,0,0,.86);
      align-items: center;
      justify-content: center;
    }
    .modal-overlay.open { display: flex; }

    .login-dialog {
      width: min(400px, calc(100vw - 32px));
      padding: 24px;
      border-radius: 14px;
      background: #fff;
      box-shadow: 0 18px 50px rgba(0,0,0,.35);
    }
    .login-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 20px; }
    .login-header h2 { color: var(--navy); font-size: 1.35rem; }
    .login-close { border: 0; background: none; color: #555; font-size: 1.6rem; cursor: pointer; }
    .login-field { margin-bottom: 14px; }
    .login-field label { display: block; margin-bottom: 6px; color: #333; font-weight: 700; }
    .login-field input {
      width: 100%; padding: 11px 12px; border: 1px solid #ccc; border-radius: 8px; font: inherit;
    }
    .login-error { display: none; margin: 4px 0 14px; color: #c51f20; font-size: .9rem; }
    .login-submit {
      width: 100%; padding: 12px; border: 0; border-radius: 8px; background: var(--red);
      color: #fff; font: inherit; font-weight: 800; cursor: pointer;
    }
    .login-submit:disabled { opacity: .65; cursor: wait; }

    .modal-box {
      position: relative;
      width: min(92vw, 960px);
      aspect-ratio: 16/9;
      background: #000;
      border-radius: 10px;
      overflow: hidden;
      box-shadow: 0 12px 60px rgba(0,0,0,.7);
    }
    .modal-box video { width: 100%; height: 100%; object-fit: contain; }

    .modal-title {
      position: absolute;
      top: -40px;
      left: 0;
      color: rgba(255,255,255,.75);
      font-size: .85rem;
      font-weight: 700;
    }
    .modal-close {
      position: absolute;
      top: -44px;
      right: 0;
      background: none;
      border: none;
      color: #fff;
      font-size: 2.2rem;
      line-height: 1;
      cursor: pointer;
      padding: 4px 8px;
    }
    .modal-close:hover { opacity: .7; }

    .disabled-link {
      pointer-events: none;  /* 클릭 불가 */
      color: gray;           /* 비활성화된 느낌 */
      text-decoration: none;
    }

    /* ══ RESPONSIVE ══ */
    @media (max-width: 780px) {
      nav { display: none; }
      .hamburger { display: flex; }
      .play-btn { width: 60px; height: 60px; }
      .play-btn svg { width: 26px; height: 26px; }
    }
  </style>
</head>
<body>

<!-- ══ HEADER ══ -->
<header>
  <div class="logo">대치동<span>셈수학</span></div>

  <nav id="desktopNav">
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">유치원</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">어린이집</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">셈수학</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">기하셈</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">늘봄학교</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">쇼핑몰</button>
    <a href="#" class="btn-primary" data-action="login">로그인</a>
  </nav>

  <button class="hamburger" id="hamburger" aria-label="메뉴">
    <span></span><span></span><span></span>
  </button>
</header>

<!-- 모바일 메뉴 드로어 -->
<div class="mobile-menu" id="mobileMenu">
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">유치원</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">어린이집</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">셈수학</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">기하셈</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">늘봄학교</button>
    <button onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach_ele.mp4','초등부 소개')">쇼핑몰</button>
    <hr/>
    <a href="#" class="btn-primary" data-action="login">로그인</a>
</div>

<!-- ══ COVER — 새 이미지 + 기존 영상 ══ -->
<div id="cover" role="button" tabindex="0"
     aria-label="대치동 수리셈 소개 영상 재생"
     onclick="playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach.mp4','대치동 수리셈 소개')"
     onkeydown="if(event.key==='Enter'||event.key===' ')playVideo('https://www.eplat.co.kr/skl_folder/mp3/sam_mach.mp4','대치동 수리셈 소개')">
  <img
    src="data:image/png;base64,"
    alt="대치동 수리셈 – 초등심화를 위한 중등개념, 주2회 3시간 수업만으로 중등 개념 완성"
  />
  <div class="play-btn">
    <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path d="M8 5v14l11-7z"/></svg>
  </div>
  <div class="online-study-wrap">
    <button type="button" class="online-study-btn" id="onlineStudyBtn">온라인 학습관</button>
  </div>
</div>

<!-- ══ LOGIN MODAL ══ -->
<div class="modal-overlay" id="loginModal" role="dialog" aria-modal="true" aria-labelledby="loginTitle">
  <div class="login-dialog">
    <div class="login-header">
      <h2 id="loginTitle">로그인</h2>
      <button type="button" class="login-close" id="loginClose" aria-label="닫기">×</button>
    </div>
    <form id="loginForm" autocomplete="on">
      <div class="login-field">
        <label for="loginEmail">아이디</label>
        <input type="text" id="loginEmail" name="Email" autocomplete="username" maxlength="40"
               pattern="[A-Za-z0-9가-힣ㄱ-ㅎㅏ-ㅣ._@-]{2,40}" required>
      </div>
      <div class="login-field">
        <label for="loginPassword">비밀번호</label>
        <input type="password" id="loginPassword" name="Password" autocomplete="current-password"
               maxlength="100" required>
      </div>
      <p class="login-error" id="loginError" role="alert"></p>
      <button type="submit" class="login-submit" id="loginSubmit">로그인</button>
    </form>
  </div>
</div>

<!-- ══ VIDEO MODAL ══ -->
<div class="modal-overlay" id="modal">
  <div class="modal-box">
    <span class="modal-title" id="modalTitle"></span>
    <button class="modal-close" id="modalClose" aria-label="닫기">✕</button>
    <video id="modalVideo" controls playsinline>
      이 브라우저는 동영상을 지원하지 않습니다.
    </video>
  </div>
</div>

<script>
  const cover = document.getElementById('cover');
  const coverImage = cover.querySelector('img');
  cover.style.backgroundImage = `url("${coverImage.src}")`;
  coverImage.remove();

  /* ── Video 모달 ── */
  const modal      = document.getElementById('modal');
  const modalVideo = document.getElementById('modalVideo');
  const modalTitle = document.getElementById('modalTitle');
  const modalClose = document.getElementById('modalClose');

  function playVideo(src, title) {
    modalTitle.textContent = title || '';
    modalVideo.src = src;
    modal.classList.add('open');
    document.body.style.overflow = 'hidden';
    modalVideo.load();
    modalVideo.play().catch(() => {});
  }

  function closeModal() {
    modal.classList.remove('open');
    document.body.style.overflow = '';
    modalVideo.pause();
    modalVideo.src = '';
  }

  modalClose.addEventListener('click', closeModal);
  modal.addEventListener('click', e => { if (e.target === modal) closeModal(); });
  document.addEventListener('keydown', e => { if (e.key === 'Escape') closeModal(); });

  /* ── 햄버거 메뉴 ── */
  const hamburger  = document.getElementById('hamburger');
  const desktopNav = document.getElementById('desktopNav');
  const mobileMenu = document.getElementById('mobileMenu');

  hamburger.addEventListener('click', () => mobileMenu.classList.toggle('open'));

  function closeMobile() { mobileMenu.classList.remove('open'); }

  document.addEventListener('click', e => {
    if (!hamburger.contains(e.target) && !mobileMenu.contains(e.target)) closeMobile();
  });

  /* ── welcome.php와 동일한 로그인 처리 ── */
  const loginModal = document.getElementById('loginModal');
  const loginForm = document.getElementById('loginForm');
  const loginEmail = document.getElementById('loginEmail');
  const loginPassword = document.getElementById('loginPassword');
  const loginError = document.getElementById('loginError');
  const loginSubmit = document.getElementById('loginSubmit');
  const loginIdPattern = /^[A-Za-z0-9가-힣ㄱ-ㅎㅏ-ㅣ._@-]{2,40}$/;
  let loginInfo = getLocalStorage('infochaitalk');
  let loginSubmitting = false;

  const roleMenus = {
    admin: [
      ['게시판', 'board/boardmgr.php'],
      ['지사관리', 'purchase/branchmgr.php'],
      ['주문관리', 'purchase/order.php'],
      ['사용자관리', 'study/vol_manage.php'],
      ['학습현황', 'study/study_stats.php']
    ],
    branch: [
      ['게시판', 'board/boardmgr.php'],
      ['지사관리', 'purchase/branchmgr.php'],
      ['주문관리', 'purchase/order.php']
    ],
    teacher: [
      ['게시판', 'board/boardmgr.php'],
      ['유치원관리', 'purchase/kgardenmgr.php']
    ]
  };

  function renderNavigation() {
    const isLoggedIn = Boolean(loginInfo && loginInfo.user);
    if (!isLoggedIn) return;

    const role = String(loginInfo.role ?? '0').toLowerCase();
    let items = [];
    if (role === '9' || role === 'admin') items = roleMenus.admin;
    else if (role === '1') items = roleMenus.branch;
    else if (role === '2') items = roleMenus.teacher;

    [desktopNav, mobileMenu].forEach(menu => {
      menu.innerHTML = '';
      items.forEach(([text, href]) => {
        const link = document.createElement('a');
        link.href = href;
        link.textContent = text;
        menu.appendChild(link);
      });
      if (menu === mobileMenu) menu.appendChild(document.createElement('hr'));
      const logout = document.createElement('a');
      logout.href = '#';
      logout.className = 'btn-primary';
      logout.dataset.action = 'logout';
      logout.textContent = '로그아웃';
      menu.appendChild(logout);
    });
  }

  function openLogin() {
    loginError.style.display = 'none';
    loginModal.classList.add('open');
    document.body.style.overflow = 'hidden';
    setTimeout(() => loginEmail.focus(), 0);
  }

  function closeLogin() {
    loginModal.classList.remove('open');
    document.body.style.overflow = '';
    loginError.style.display = 'none';
  }

  [desktopNav, mobileMenu].forEach(menu => {
    menu.addEventListener('click', event => {
      const actionLink = event.target.closest('[data-action]');
      if (!actionLink) {
        if (menu === mobileMenu) closeMobile();
        return;
      }
      event.preventDefault();
      closeMobile();
      if (actionLink.dataset.action === 'logout') {
        deleteLocalStorage('infochaitalk');
        loginInfo = null;
        window.location.reload();
      } else {
        openLogin();
      }
    });
  });

  const onlineStudyBtn = document.getElementById('onlineStudyBtn');
  onlineStudyBtn.addEventListener('keydown', event => event.stopPropagation());
  onlineStudyBtn.addEventListener('click', event => {
    event.stopPropagation();
    if (loginInfo && loginInfo.user) window.location.href = 'study/wordpen.php';
    else openLogin();
  });

  document.getElementById('loginClose').addEventListener('click', closeLogin);
  loginModal.addEventListener('click', event => {
    if (event.target === loginModal) closeLogin();
  });

  loginForm.addEventListener('submit', event => {
    event.preventDefault();
    if (loginSubmitting) return;

    const email = loginEmail.value.trim();
    const password = loginPassword.value;
    loginError.style.display = 'none';
    if (!loginIdPattern.test(email) || !password || password.length > 100) {
      loginError.textContent = '아이디 또는 비밀번호 형식이 올바르지 않습니다.';
      loginError.style.display = 'block';
      return;
    }

    const formData = new FormData(loginForm);
    formData.set('Email', email);
    formData.set('Password', password);
    formData.append('functionName', 'Slogon');
    loginSubmitting = true;
    loginSubmit.disabled = true;
    loginSubmit.textContent = '로그인 중...';

    const showLoginError = message => {
      loginError.textContent = message;
      loginError.style.display = 'block';
      loginPassword.value = '';
    };
    const dest = new URLSearchParams(location.search).get('dest') || '';
    CallAjax1(`SMethods.php?dest=${encodeURIComponent(dest)}`, 'POST', formData, response => {
      if (response.success && response.success[0]) {
        const login = response.success[0];
        loginInfo = {
          user: login.user, role: login.role, conf: login.confirm, name: login.name,
          owner: login.owner, loca: login.location, step: login.step, clas: login.clas,
          loginAt: Date.now()
        };
        saveLocalStorage('infochaitalk', loginInfo);
        loginPassword.value = '';
        renderNavigation();
        closeLogin();
      } else {
        showLoginError('아이디 또는 비밀번호가 잘못되었습니다.');
      }
      loginSubmitting = false;
      loginSubmit.disabled = false;
      loginSubmit.textContent = '로그인';
    }, error => {
      const detail = error?.responseJSON?.message || error?.message || error?.statusText;
      showLoginError(detail ? `로그인 처리 오류: ${detail}` : '로그인 처리 중 오류가 발생했습니다.');
      loginSubmitting = false;
      loginSubmit.disabled = false;
      loginSubmit.textContent = '로그인';
    });
  });

  document.addEventListener('keydown', event => {
    if (event.key === 'Escape' && loginModal.classList.contains('open')) closeLogin();
  });
  renderNavigation();
</script>

</body>
</html>
